document.addEventListener("alpine:init",()=>{Alpine.data("inlineConfirmAction",({timeout:e})=>({armed:!1,processing:!1,timer:null,arm(){this.armed=!0,this.timer=setTimeout(()=>this.disarm(),e)},disarm(){clearTimeout(this.timer),this.armed=!1,this.processing=!1},process(){clearTimeout(this.timer),this.processing=!0}}))});
